import psycopg2
from psycopg2 import Error


def search_users(**kwargs):
    """
    Search for users based on the provided criteria.

    Parameters:
        kwargs (dict): A dictionary containing the search criteria.
            Keys are the field names and values are the corresponding values to be searched.

    Returns:
        list: A list of dictionaries, each representing a user record.

    Raises:
        psycopg2.Error: If there is an error connecting to or querying the database.
    """
    try:
        conn = psycopg2.connect(
            host="localhost",
            port=5432,
            dbname="postgres",
            user="postgres",
            password="<PASSWORD>"
        )

        cursor = conn.cursor()

        # Build the SQL query based on the provided search criteria
        sql_query = "SELECT * FROM users WHERE 1=1"
        for field in kwargs:
            if kwargs[field] is not None and len(kwargs[field]) > 0:
                sql_query += f' AND {field} LIKE \'%{kwargs[field]}%\''

        # Execute the query and fetch all results
        cursor.execute(sql_query)
        users = cursor.fetchall()

        return [dict(zip([col[0] for col in cursor.description], row))
                for row in users]

    except (Exception, psycopg2.Error) as error:
        print("Error while connecting to PostgreSQL", error)
    finally:
        # Close the database connection
        if conn is not None:
            conn.close()


if __name__ == "__main__":
    # Sample usage
    results = search_users(username="john")  # Search by username
    results = search_users(role="admin")  # Search by role
    results = search_users(status="active", role="user")  # Search by status and role